    setBestLift(stats.bestLift);
    setWeeklyBurned(stats.totalCaloriesBurned);
    setWeeklyIn(stats.totalCaloriesIn);
    setHeatmapData(getMuscleHeatmapData());
  };

  // Save session effect
  useEffect(() => {
    if (currentUser) saveSession(currentSession);
  }, [currentSession, currentUser]);

  // Save stats effect
  useEffect(() => {
    if (currentUser && userStats) saveUserStats(userStats);
  }, [userStats, currentUser]);

  // Session Timer Effect
  useEffect(() => {
    let interval: ReturnType<typeof setInterval>;
    if (view === 'WORKOUT' && currentSession && !currentSession.isFinished) {
        setElapsedTime(Math.floor((Date.now() - currentSession.startTime) / 1000));
        interval = setInterval(() => {
            setElapsedTime(Math.floor((Date.now() - currentSession.startTime) / 1000));
        }, 1000);
    }
    return () => clearInterval(interval);
  }, [view, currentSession?.startTime, currentSession?.isFinished]);

  // --- HANDLERS ---

  const handleLogin = () => {
    const user = getCurrentUser();
    setCurrentUser(user);
    loadUserData();
  };

  const handleLogout = () => {
    setCurrentUser(null);
    setCurrentSession(null);
    setUserStats(null);
    switchUser(''); // Clear active user in storage
  };

  const handleBackup = () => {
    exportUserData();
  };

  const handleRestoreClick = () => {
    if (fileInputRef.current) fileInputRef.current.click();
  };

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const success = await importUserData(file);
      if (success) {
        alert("Data restored successfully! The app will reload.");
        window.location.reload();
      }
    }
  };

  const handleLogNutrition = () => {
      const cals = parseInt(foodCals);
      if (!cals) return;
      logNutrition(cals, foodName);
      setFoodCals('');
      setFoodName('');
      setShowNutritionModal(false);
      refreshDashboard();
  };

  // Determine active plan
  const getActivePlan = () => {
    if (currentSession && !currentSession.isFinished && currentSession.workoutId) {
        return ALL_WORKOUTS.find(w => w.id === currentSession.workoutId) || null;
    }
    if (selectedWorkoutId) return ALL_WORKOUTS.find(w => w.id === selectedWorkoutId) || null;
    return WORKOUT_SCHEDULE[todayIndex];
  };

  const activePlan = getActivePlan();

  const handleStartWorkout = () => {
    if (!activePlan) return;
    const newSession: SessionData = {
      workoutId: activePlan.id,
      startTime: Date.now(),
      completedExercises: {},
      customExercises: [],
      activeExerciseId: null,
      activeTimer: null,
      isFinished: false,
      swaps: {}
    };
    setCurrentSession(newSession);
    setView('WORKOUT');
  };

  const handleSelectExercise = (id: string) => {
    if (currentSession) setCurrentSession({ ...currentSession, activeExerciseId: id });
  };

  const handleBackToWorkoutList = () => {
    if (currentSession) setCurrentSession({ ...currentSession, activeExerciseId: null });
  };

  const handleAddCustomExercise = (ex: Exercise) => {
      if (currentSession) setCurrentSession({ ...currentSession, customExercises: [...(currentSession.customExercises || []), ex] });
  };

  const handleSwapExercise = (originalId: string, newId: string) => {
    if (!currentSession) return;
    const newSwaps = { ...(currentSession.swaps || {}) };
    if (originalId === newId) delete newSwaps[originalId];
    else newSwaps[originalId] = newId;
    setCurrentSession({ ...currentSession, swaps: newSwaps });
  };

  const handleLogSet = (metric1: number, metric2: number, isDropSet: boolean = false, isMonsterSet: boolean = false, rpe?: number, tempoRating?: TempoRating) => {
    if (!currentSession || !currentSession.activeExerciseId || !activePlan) return;

    const exerciseId = currentSession.activeExerciseId;
    let exercise: Exercise | undefined = currentSession.customExercises?.find(e => e.id === exerciseId);

    if (!exercise) {
        for (const ex of activePlan.exercises) {
            if (ex.id === exerciseId) { exercise = ex; break; }
            if (ex.alternatives?.find(a => a.id === exerciseId)) { exercise = ex.alternatives.find(a => a.id === exerciseId); break; }
        }
    }
    if (!exercise) return;

    const isCardio = exercise.type === 'cardio';
    const calories = calculateCalories(metric1, metric2, exercise.metValue, isCardio);

    const updatedCompleted = { ...currentSession.completedExercises };
    if (!updatedCompleted[exerciseId]) updatedCompleted[exerciseId] = [];

    const setNumber = updatedCompleted[exerciseId].length + 1;
    updatedCompleted[exerciseId].push({
      weight: metric1, reps: metric2, rpe, tempoRating, completed: true,
      timestamp: Date.now(), isDropSet, isMonsterSet, calories
    });

    saveExerciseLog(exerciseId, metric1, metric2, setNumber, rpe, tempoRating);

    const skipTimer = isDropSet || isMonsterSet;
    let newTimer = null;
    if (exercise.restSeconds > 0 && !skipTimer) {
      newTimer = {
        startTime: Date.now(),
        duration: exercise.restSeconds,
        endTime: Date.now() + (exercise.restSeconds * 1000),
        exerciseId: exerciseId
      };
    }

    setCurrentSession({ ...currentSession, completedExercises: updatedCompleted, activeTimer: newTimer });
  };

  const handleFinishWorkout = () => {
    if (currentSession) setCurrentSession({ ...currentSession, isFinished: true });
  };

  const handleCompleteWorkoutSummary = () => {
    setCurrentSession(null);
    setView('HOME');
    refreshDashboard();
  };

  const cancelTimer = () => {
    if (currentSession) setCurrentSession({ ...currentSession, activeTimer: null });
  };

  const updateWater = (amount: number) => {
    if (userStats) setUserStats({ ...userStats, waterIntake: userStats.waterIntake + amount });
  };

  const toggleCreatine = () => {
    if (!userStats) return;
    const isTaken = !userStats.creatineTaken;
    const today = getTodayString();
    let newHistory = [...userStats.creatineHistory];
    if (isTaken) { if (!newHistory.includes(today)) newHistory.push(today); } 
    else { newHistory = newHistory.filter(d => d !== today); }
    setUserStats({ ...userStats, creatineTaken: isTaken, creatineHistory: newHistory });
  };

  const formatTime = (sec: number) => {
    const h = Math.floor(sec / 3600);
    const m = Math.floor((sec % 3600) / 60);
    const s = sec % 60;
    if (h > 0) return `${h}:${m<10?'0':''}${m}:${s<10?'0':''}${s}`;
    return `${m}:${s<10?'0':''}${s}`;
  };

  const getProjectedEndTime = () => {
    if (!activePlan || !currentSession) return null;
    const effectiveExercises = activePlan.exercises.map(ex => {
       const swapId = currentSession.swaps?.[ex.id];
       return (swapId && ex.alternatives?.find(a => a.id === swapId)) || ex;
    }).concat(currentSession.customExercises || []);

    let remainingSeconds = 0;
    effectiveExercises.forEach(ex => {
        const completedCount = currentSession.completedExercises[ex.id]?.length || 0;
        const setsLeft = Math.max(0, ex.sets - completedCount);
        if (setsLeft > 0) {
            let setDuration = 45;
            if (ex.type === 'cardio') {
                 const match = ex.reps.match(/(\d+)/);
                 if (match) setDuration = parseInt(match[0]) * 60;
            }
            remainingSeconds += setsLeft * (setDuration + ex.restSeconds);
        }
    });
    if (remainingSeconds === 0) return "Finishing...";
    return new Date(Date.now() + remainingSeconds * 1000).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  };

  // --- RENDER LOGIC ---

  if (!currentUser) {
    return <LoginScreen onLogin={handleLogin} />;
  }

  if (view === 'STATS') {
    return <StatsView onBack={() => setView('HOME')} />;
  }

  if (view === 'HELP') {
    return <HelpView onBack={() => setView('HOME')} />;
  }

  if (view === 'WORKOUT' && currentSession) {
    if (currentSession.isFinished) {
      return <WorkoutReceipt data={getSessionSummary(currentSession)} onClose={handleCompleteWorkoutSummary} />;
    }

    let activeExercise: Exercise | undefined = undefined;
    if (currentSession.activeExerciseId) {
        const id = currentSession.activeExerciseId;
        activeExercise = currentSession.customExercises?.find(e => e.id === id);
        if (!activeExercise && activePlan) {
             for (const ex of activePlan.exercises) {
                if (ex.id === id) { activeExercise = ex; break; }
                if (ex.alternatives?.find(a => a.id === id)) { activeExercise = ex.alternatives.find(a => a.id === id); break; }
            }
        }
    }

    return (
      <div className="min-h-screen bg-gym-900 text-white p-4 flex flex-col max-w-md mx-auto relative overflow-hidden">
        <div className="flex justify-between items-center mb-4 z-10 bg-gym-900/90 backdrop-blur pb-2 border-b border-gym-800 sticky top-0">
           <button onClick={handleCompleteWorkoutSummary} className="text-xs text-gray-500 hover:text-white uppercase font-bold tracking-widest">Exit</button>
           <div className="flex flex-col items-end">
             <div className="flex items-center gap-2">
                 <Clock size={12} className="text-gym-accent" />
                 <span className="font-mono font-bold text-sm text-white">{formatTime(elapsedTime)}</span>
                 <div className="w-2 h-2 rounded-full bg-red-500 animate-pulse ml-1"></div>
             </div>
             <span className="text-[10px] text-gray-500">Est. End: {getProjectedEndTime() || '--:--'}</span>
           </div>
        </div>
        {activeExercise ? (
          <ExerciseCard 
            exercise={activeExercise}
            completedSets={currentSession.completedExercises[activeExercise.id] || []}
            onLogSet={handleLogSet}
            onBack={handleBackToWorkoutList}
            onUpdateWater={updateWater} // Pass the hydration function
          />
        ) : activePlan ? (
          <WorkoutView 
            plan={activePlan}
            session={currentSession}
            onSelectExercise={handleSelectExercise}
            onFinishWorkout={handleFinishWorkout}
            onAddCustomExercise={handleAddCustomExercise}
            onSwapExercise={handleSwapExercise}
          />
        ) : null}
        {currentSession.activeTimer && <Timer activeTimer={currentSession.activeTimer} onCancel={cancelTimer} onComplete={cancelTimer} />}
      </div>
    );
  }

  if (view === 'SETTINGS') {
    return (
      <div className="min-h-screen bg-gym-900 text-white p-6 max-w-md mx-auto">
        <div className="flex items-center gap-4 mb-8">
          <button onClick={() => setView('HOME')} className="text-gray-400 hover:text-white"><ArrowLeft className="rotate-180" /></button>
          <h2 className="text-2xl font-bold">Settings</h2>
        </div>

        <div className="space-y-6">
          {/* User Profile */}
          <div className="bg-gym-800 p-4 rounded-xl border border-gym-700">
             <div className="flex items-center gap-4 mb-4">
               <div className="p-3 bg-gym-900 rounded-full text-gym-accent"><UserCircle2 size={24}/></div>
               <div>
                 <p className="text-xs text-gray-500 font-bold uppercase">Current Athlete</p>
                 <p className="text-xl font-bold text-white">{currentUser.name}</p>
               </div>
             </div>
             <button onClick={handleLogout} className="w-full py-2 bg-gym-700 text-white rounded-lg font-bold text-sm flex items-center justify-center gap-2 hover:bg-gym-600"><LogOut size={16}/> Switch User / Logout</button>
          </div>

          {/* Backup & Restore */}
          <div className="bg-gym-800 p-4 rounded-xl border border-gym-700">
            <h3 className="font-bold mb-4 text-white flex items-center gap-2">Data Management</h3>
            <div className="grid grid-cols-2 gap-3">
               <button onClick={handleBackup} className="py-3 bg-blue-600/20 text-blue-400 border border-blue-600/30 rounded-lg font-bold text-sm flex flex-col items-center gap-1 hover:bg-blue-600/30">
                  <Download size={20} /> Backup Data
               </button>
               <button onClick={handleRestoreClick} className="py-3 bg-orange-600/20 text-orange-400 border border-orange-600/30 rounded-lg font-bold text-sm flex flex-col items-center gap-1 hover:bg-orange-600/30">
                  <Upload size={20} /> Restore Data
               </button>
               <input type="file" ref={fileInputRef} className="hidden" accept=".json" onChange={handleFileChange} />
            </div>
            <p className="text-[10px] text-gray-500 mt-2">Backups are specific to {currentUser.name}.</p>
          </div>

          {/* Danger Zone */}
          <div className="bg-gym-800 p-4 rounded-xl border border-gym-700">
            <h3 className="font-bold mb-2 text-red-400 flex items-center gap-2"><Trash2 size={18} /> Danger Zone</h3>
            <p className="text-sm text-gray-400 mb-4">Reset all progress for <strong>{currentUser.name}</strong>. Cannot be undone.</p>
            <button onClick={() => { if(confirm("Are you sure?")) clearAllData(); }} className="w-full py-3 border border-red-500/50 text-red-500 rounded-lg hover:bg-red-500/10 font-bold uppercase text-sm">Reset Profile Data</button>
          </div>
        </div>
      </div>
    );
  }

  // --- RENDER: DASHBOARD (HOME) ---
  return (
    <div className="min-h-screen bg-gym-900 text-white p-6 max-w-md mx-auto font-sans flex flex-col relative">

      {/* NUTRITION MODAL */}
      {showNutritionModal && (
          <div className="fixed inset-0 z-[80] bg-gym-900/95 backdrop-blur flex flex-col items-center justify-center p-6 animate-in fade-in">
              <div className="bg-gym-800 w-full rounded-2xl border border-gym-700 p-6 relative shadow-2xl">
                  <button onClick={() => setShowNutritionModal(false)} className="absolute top-4 right-4 text-gray-400 hover:text-white">
                      <X size={24} />
                  </button>

                  <h3 className="text-2xl font-black text-white mb-6 flex items-center gap-2">
                      <Utensils className="text-gym-accent" /> Log Meal
                  </h3>

                  <div className="space-y-4">
                      <div>
                          <label className="text-xs font-bold text-gray-500 uppercase">Estimated Calories</label>
                          <input 
                            type="number" 
                            autoFocus
                            placeholder="e.g. 500" 
                            value={foodCals}
                            onChange={(e) => setFoodCals(e.target.value)}
                            className="w-full bg-gym-900 border border-gym-600 rounded-xl p-4 text-3xl text-white font-bold text-center focus:border-gym-accent focus:outline-none"
                          />
                      </div>
                      <div>
                          <label className="text-xs font-bold text-gray-500 uppercase">Food Name (Optional)</label>
                          <input 
                            type="text" 
                            placeholder="e.g. Chicken Rice" 
                            value={foodName}
                            onChange={(e) => setFoodName(e.target.value)}
                            className="w-full bg-gym-900 border border-gym-600 rounded-xl p-3 text-white text-center focus:border-gym-accent focus:outline-none"
                          />
                      </div>

                      <button 
                        onClick={handleLogNutrition}
                        disabled={!foodCals}
                        className="w-full py-4 bg-gym-accent hover:bg-blue-600 disabled:opacity-50 disabled:cursor-not-allowed text-white font-bold rounded-xl shadow-lg mt-4 flex items-center justify-center gap-2"
                      >
                          <Plus size={20} /> Add to Log
                      </button>
                  </div>
              </div>
          </div>
      )}

      <header className="flex justify-between items-center mb-6">
        <div>
          <h1 className="text-2xl font-black tracking-tighter text-white italic">IRON<span className="text-gym-accent">GUIDE</span></h1>
          <p className="text-[10px] text-gray-500 font-mono tracking-[0.2em] uppercase">Hypertrophy Blueprint</p>
        </div>
        <div className="flex gap-2">
          <button onClick={() => setView('HELP')} className="w-10 h-10 rounded-full bg-gym-800 flex items-center justify-center border border-gym-700 hover:bg-gym-700 text-gray-400 hover:text-white" title="App Guide"><HelpCircle size={20} /></button>
          <button onClick={() => setView('STATS')} className="w-10 h-10 rounded-full bg-gym-800 flex items-center justify-center border border-gym-700 hover:bg-gym-700 text-gym-accent"><BarChart3 size={20} /></button>
          <button onClick={() => setView('SETTINGS')} className="w-10 h-10 rounded-full bg-gym-800 flex items-center justify-center border border-gym-700 hover:bg-gym-700"><UserCircle2 className="text-gray-400" /></button>
        </div>
      </header>

      {/* Hero Stats */}
      <div className="grid grid-cols-2 gap-3 mb-6">
        <div className="bg-gym-800/30 rounded-lg p-3 border border-gym-700">
           <div className="flex items-center gap-2 mb-2"><Trophy size={14} className="text-yellow-500" /><p className="text-[10px] text-gray-400 uppercase font-bold">Best Lift</p></div>
           {bestLift ? (<div><p className="text-sm font-bold text-white truncate">{bestLift.exerciseName}</p><p className="text-lg font-black text-gym-accent italic">{bestLift.weight}kg</p></div>) : (<p className="text-xs text-gray-500 italic">No logs yet</p>)}
        </div>

        {/* ENERGY BALANCE CARD */}
        <div className="bg-gym-800/30 rounded-lg p-3 border border-gym-700 relative overflow-hidden group">
           <div className="flex items-center justify-between mb-1 relative z-10">
               <div className="flex items-center gap-2"><Flame size={14} className="text-orange-500" /><p className="text-[10px] text-gray-400 uppercase font-bold">Energy Balance</p></div>
               <button onClick={() => setShowNutritionModal(true)} className="p-1 bg-gym-800 rounded text-gym-accent hover:bg-gym-700 transition-colors"><Plus size={12} /></button>
           </div>
           <div className="relative z-10 flex justify-between items-end">
               <div>
                   <p className="text-[9px] text-orange-400 uppercase">Burned</p>
                   <p className="text-sm font-black text-white">{weeklyBurned}</p>
               </div>
               <div className="h-6 w-px bg-gym-700"></div>
               <div className="text-right">
                   <p className="text-[9px] text-green-400 uppercase">Intake</p>
                   <p className="text-sm font-black text-white">{weeklyIn}</p>
               </div>
           </div>
        </div>
      </div>

      <div className="mb-6 animate-in fade-in slide-in-from-bottom-2"><BodyHeatmap recoveryStatus={heatmapData} /></div>

      <div className="mb-8 flex-1">
        <div className="flex justify-between items-baseline mb-3">
          <div className="flex gap-2 items-center">
            <h2 className="text-gray-400 text-sm uppercase font-bold tracking-wider">{selectedWorkoutId ? 'Custom Plan' : DAYS_OF_WEEK[todayIndex]}</h2>
            <button onClick={() => setShowWorkoutSelector(!showWorkoutSelector)} className="text-xs text-gym-accent flex items-center gap-1 hover:underline"><Edit2 size={10} /> Change</button>
          </div>
          <span className="text-xs text-gym-accent font-mono">{getTodayString()}</span>
        </div>

        {showWorkoutSelector && (
          <div className="mb-4 grid grid-cols-1 gap-2 animate-in slide-in-from-top-2">
            {ALL_WORKOUTS.map(w => (
              <button key={w.id} onClick={() => { setSelectedWorkoutId(w.id); setShowWorkoutSelector(false); }} className={`p-3 rounded-lg text-left text-sm font-bold border transition-all flex items-center justify-between ${(selectedWorkoutId === w.id) || (!selectedWorkoutId && WORKOUT_SCHEDULE[todayIndex]?.id === w.id) ? 'bg-gym-accent text-white border-blue-400' : 'bg-gym-800 text-gray-400 border-gym-700 hover:bg-gym-700'}`}>{w.name}</button>
            ))}
             <button onClick={() => { setSelectedWorkoutId(null); setShowWorkoutSelector(false); }} className="text-xs text-center text-gray-500 py-1">Reset to Schedule</button>
          </div>
        )}

        {activePlan ? (
          <div className="bg-gradient-to-br from-gym-800 to-gym-900 border border-gym-700 rounded-2xl p-6 shadow-2xl relative overflow-hidden group">
            <div className="absolute top-0 right-0 w-40 h-40 bg-blue-500/5 rounded-full blur-3xl -mr-16 -mt-16 pointer-events-none"></div>
            <div className="relative z-10">
              <h3 className="text-3xl font-bold text-white mb-2 leading-none">{activePlan.name.split(':')[0]}</h3>
              <p className="text-sm text-gray-300 mb-6 font-medium border-l-2 border-gym-accent pl-3 py-1">{activePlan.focus}</p>
              <div className="flex items-center gap-6 text-sm text-gray-400 mb-8">
                 <div className="flex flex-col"><span className="font-bold text-white text-xl">{activePlan.exercises.length}</span><span className="text-[10px] uppercase tracking-wide">Exercises</span></div>
                 <div className="w-px h-8 bg-gym-700"></div>
                 <div className="flex flex-col"><span className="font-bold text-white text-xl">~50</span><span className="text-[10px] uppercase tracking-wide">Minutes</span></div>
              </div>
              <button onClick={handleStartWorkout} className="w-full py-4 bg-gym-accent hover:bg-blue-600 active:scale-95 transition-all text-white font-bold rounded-xl flex items-center justify-center gap-2 shadow-lg shadow-blue-900/20 text-lg">Start Workout <ArrowRight size={20} /></button>
            </div>
          </div>
        ) : (
          <div className="bg-gym-800 border border-gym-700 rounded-2xl p-8 text-center opacity-80 flex flex-col items-center justify-center h-64">
            <Battery className="text-gym-success mb-4" size={40} />
            <h3 className="text-2xl font-bold text-white mb-2">Rest & Grow</h3>
            <p className="text-gray-400 mb-4 max-w-[200px]">"Muscle is built in the recovery, not the gym."</p>
            <button onClick={() => setShowWorkoutSelector(true)} className="text-sm text-gym-accent underline">Do a workout anyway</button>
          </div>
        )}
      </div>

      <div className="grid grid-cols-2 gap-4 mb-4">
        <div className="bg-gym-800 rounded-xl p-4 border border-gym-700 flex flex-col justify-between h-48 relative overflow-hidden shadow-lg">
           <div className="absolute bottom-0 left-0 right-0 bg-blue-500/10 transition-all duration-700 ease-out" style={{ height: `${Math.min(((userStats?.waterIntake || 0) / 4000) * 100, 100)}%` }}></div>
           <div className="relative z-10 flex justify-between items-start mb-2"><div className="p-2 bg-gym-900/50 rounded-lg"><Droplets size={20} className="text-blue-400" /></div><span className="text-[10px] font-mono text-gray-400 uppercase">Goal: 4L</span></div>
           <div className="relative z-10 text-center mb-2"><div className="text-2xl font-bold text-white">{userStats?.waterIntake || 0}<span className="text-sm font-normal text-gray-500">ml</span></div></div>
           <div className="relative z-10 grid grid-cols-3 gap-1">
             <button onClick={() => updateWater(30)} className="bg-blue-900/40 hover:bg-blue-800 text-blue-200 text-[10px] py-2 rounded font-bold border border-blue-500/20">Sip</button>
             <button onClick={() => updateWater(100)} className="bg-blue-900/40 hover:bg-blue-800 text-blue-200 text-[10px] py-2 rounded font-bold border border-blue-500/20">Gulp</button>
             <button onClick={() => updateWater(250)} className="bg-blue-900/40 hover:bg-blue-800 text-blue-200 text-[10px] py-2 rounded font-bold border border-blue-500/20">Glass</button>
           </div>
        </div>
        <button onClick={toggleCreatine} className={`rounded-xl p-4 border cursor-pointer transition-all h-48 flex flex-col justify-between shadow-lg group relative overflow-hidden ${userStats?.creatineTaken ? 'bg-gym-success/10 border-gym-success/30' : 'bg-gym-800 border-gym-700'}`}>
           {userStats?.creatineTaken && <div className="absolute inset-0 bg-gym-success/5 animate-pulse"></div>}
           <div className="flex justify-between items-start relative z-10"><div className={`p-2 rounded-lg transition-colors ${userStats?.creatineTaken ? 'bg-gym-success/20' : 'bg-gym-900/50'}`}><Battery size={20} className={userStats?.creatineTaken ? 'text-gym-success' : 'text-gray-400'} /></div></div>
           <div className="relative z-10 text-left">
             <div className={`text-xl font-bold transition-colors ${userStats?.creatineTaken ? 'text-gym-success' : 'text-gray-300'}`}>{userStats?.creatineTaken ? 'Taken' : 'Creatine'}</div>
             <div className="flex gap-2 mt-3"><div className="flex flex-col"><span className="text-[10px] text-gray-500 uppercase">Week</span><span className="text-sm font-bold text-white">{getCreatineStats(userStats?.creatineHistory || []).thisWeek}/7</span></div><div className="w-px bg-gray-700"></div><div className="flex flex-col"><span className="text-[10px] text-gray-500 uppercase">Month</span><span className="text-sm font-bold text-white">{getCreatineStats(userStats?.creatineHistory || []).thisMonth}</span></div></div>
