const MotionTracker: React.FC<Props> = ({ exercise, onRepCount, onClose, targetReps }) => {
  // --- STATE ---
  const [isActive, setIsActive] = useState(false);
  const [isPaused, setIsPaused] = useState(false);
  const [reps, setReps] = useState(0);
  const [processorEvent, setProcessorEvent] = useState<MotionEvent | null>(null);
  const [phonePosition, setPhonePosition] = useState<Position>('HAND');
  const [isMutedState, setIsMutedState] = useState(false);
  const [isHapticsEnabledState, setIsHapticsEnabledState] = useState(true);
  const [permissionState, setPermissionState] = useState<'prompt' | 'granted' | 'denied'>('prompt');

  // --- REFS ---
  const synthRef = useRef<SpeechSynthesis | null>(null);
  const processorRef = useRef<MotionProcessor | null>(null);
  const isMutedRef = useRef(false);
  const isHapticsEnabledRef = useRef(true);

  // --- INIT ---
  useEffect(() => {
    if ('speechSynthesis' in window) synthRef.current = window.speechSynthesis;

    // Auto-detect position based on exercise
    if (exercise.targetGroup === 'Legs') setPhonePosition('POCKET');

    return () => {
        if (synthRef.current) synthRef.current.cancel();
        window.removeEventListener('deviceorientation', handleOrientation);
    };
  }, []);

  const handleOrientation = (event: DeviceOrientationEvent) => {
    if (processorRef.current && !isPaused) {
      processorRef.current.process(event.alpha, event.beta, event.gamma);
    }
  };

  const requestPermission = async () => {
    if (typeof (DeviceOrientationEvent as any).requestPermission === 'function') {
      try {
        const response = await (DeviceOrientationEvent as any).requestPermission();
        if (response === 'granted') {
          setPermissionState('granted');
          initProcessor();
        } else {
          setPermissionState('denied');
        }
      } catch (e) {
        console.error(e);
      }
    } else {
      setPermissionState('granted');
      initProcessor();
    }
  };

  const initProcessor = () => {
    processorRef.current = new MotionProcessor(
      exercise,
      phonePosition,
      (event) => {
        setProcessorEvent(event);

        // Audio/Haptic triggers on phase change
        if (event.feedback && event.feedbackType) {
          speak(event.feedback);
          if (event.feedbackType === 'TOO_FAST') triggerHaptic([100, 50, 100]);
        }

        if (event.repCount > reps) {
          setReps(event.repCount);
          onRepCount(event.repCount);
          speak(String(event.repCount));
          triggerHaptic([100, 50, 100]);
        }
      }
    );

    window.addEventListener('deviceorientation', handleOrientation);
    processorRef.current.startCalibration();
    setIsActive(true);
  };

  // --- AUDIO & HAPTICS ---
  const speak = (text: string) => {
    if (isMutedRef.current || !synthRef.current) return;
    synthRef.current.cancel();
    const u = new SpeechSynthesisUtterance(text);
    u.rate = 1.0;
    synthRef.current.speak(u);
  };

  const triggerHaptic = (pattern: number[]) => {
    if (!isHapticsEnabledRef.current || !navigator.vibrate) return;
    navigator.vibrate(pattern);
  };

  const toggleMute = () => {
    isMutedRef.current = !isMutedRef.current;
    setIsMutedState(isMutedRef.current);
  };

  const toggleHaptics = () => {
    isHapticsEnabledRef.current = !isHapticsEnabledRef.current;
    setIsHapticsEnabledState(isHapticsEnabledRef.current);
  };

  const handleCalibrationFinished = () => {
    if (processorRef.current) {
      processorRef.current.finishCalibration();
      speak("Calibration complete. Start your set.");
    }
  };

  // --- RENDER HELPERS ---
  const progress = processorEvent?.progress || 0;
  const phase = processorEvent?.phase || 'IDLE';

  if (permissionState === 'prompt') {
    return (
      <div className="fixed inset-0 z-[60] bg-gym-900 flex flex-col items-center justify-center p-8 text-center animate-in fade-in">
        <Smartphone size={64} className="text-gym-accent mb-6 animate-bounce" />
        <h2 className="text-3xl font-black text-white mb-4">Motion Guard</h2>
        <p className="text-gray-400 mb-8">We use your phone's sensors to track your tempo and range of motion. For best results, keep the phone in the same spot.</p>

        <div className="w-full bg-gym-800 p-4 rounded-2xl border border-gym-700 mb-8">
          <p className="text-[10px] text-gray-500 uppercase font-bold mb-4">Where is your phone?</p>
          <div className="flex gap-2">
            <button 
              onClick={() => setPhonePosition('HAND')}
              className={`flex-1 py-4 rounded-xl border font-bold transition-all ${phonePosition === 'HAND' ? 'bg-gym-accent border-blue-400 text-white shadow-lg shadow-blue-500/20' : 'bg-gym-900 border-gym-700 text-gray-500'}`}
            >
              Hand / Wrist
            </button>
            <button 
              onClick={() => setPhonePosition('POCKET')}
              className={`flex-1 py-4 rounded-xl border font-bold transition-all ${phonePosition === 'POCKET' ? 'bg-gym-accent border-blue-400 text-white shadow-lg shadow-blue-500/20' : 'bg-gym-900 border-gym-700 text-gray-500'}`}
            >
              Pocket
            </button>
          </div>
        </div>

        <button 
          onClick={requestPermission}
          className="w-full py-5 bg-white text-gym-900 font-black rounded-2xl shadow-xl active:scale-95 transition-transform"
        >
          START TRACKING
        </button>
        <button onClick={onClose} className="mt-6 text-gray-500 font-bold hover:text-white">Cancel</button>
      </div>
    );
  }

  return (
    <div className="fixed inset-0 z-[60] bg-gym-900 flex flex-col animate-in fade-in duration-300">
      {/* HEADER */}
      <div className="p-4 flex justify-between items-center border-b border-gym-700 bg-gym-800">
        <div>
          <h3 className="font-bold text-white text-lg">{exercise.name}</h3>
          <div className="flex items-center gap-2">
            <span className={`w-2 h-2 rounded-full ${phase === 'CALIBRATING' ? 'bg-yellow-500 animate-pulse' : 'bg-gym-success'}`}></span>
            <p className="text-xs text-gym-accent font-mono tracking-widest uppercase">{phase}</p>
          </div>
        </div>
        <div className="flex gap-3">
          <button onClick={toggleHaptics} className={`p-2 rounded-full ${isHapticsEnabledState ? 'text-white bg-gym-700' : 'text-gray-600'}`}><Waves size={20}/></button>
          <button onClick={toggleMute} className={`p-2 rounded-full ${!isMutedState ? 'text-white bg-gym-700' : 'text-gray-600'}`}>{isMutedState ? <VolumeX size={20}/> : <Volume2 size={20}/>}</button>
          <button onClick={onClose} className="p-2 bg-gym-700 rounded-full text-white"><X size={20}/></button>
        </div>
      </div>

      {/* MAIN TRACKER VIEW */}
      <div className="flex-1 flex flex-col items-center justify-center p-6 relative">

        {/* CALIBRATION OVERLAY */}
        {phase === 'CALIBRATING' ? (
          <div className="text-center animate-in zoom-in">
            <div className="w-48 h-48 bg-gym-800 rounded-full border-4 border-dashed border-gym-accent flex items-center justify-center mx-auto mb-8 animate-[spin_10s_linear_infinite]">
                <Target size={64} className="text-gym-accent -rotate-[inherit]" />
            </div>
            <h2 className="text-4xl font-black text-white mb-2">CALIBRATING</h2>
            <p className="text-gray-400 max-w-[250px] mx-auto mb-8">Perform one slow repetition through your full range of motion.</p>
            <button 
              onClick={handleCalibrationFinished}
              className="px-10 py-4 bg-gym-accent text-white font-black rounded-2xl shadow-lg"
            >
              DONE MOVING
            </button>
          </div>
        ) : (
          <>
            {/* LIVE FEEDBACK TEXT */}
            <div className="absolute top-10 w-full text-center">
                {processorEvent?.feedbackType === 'TOO_FAST' && (
                  <div className="inline-flex items-center gap-2 px-4 py-2 bg-red-500 text-white font-black rounded-full animate-bounce">
                    <AlertTriangle size={18} /> SLOW DOWN
                  </div>
                )}
                {processorEvent?.feedbackType === 'PERFECT' && (
                  <div className="inline-flex items-center gap-2 px-4 py-2 bg-gym-success text-white font-black rounded-full animate-in fade-in">
                    <CheckCircle2 size={18} /> PERFECT TEMPO
                  </div>
                )}
            </div>

            {/* PACER CIRCLE */}
            <div className="relative scale-110">
              <div className={`w-72 h-72 rounded-full border-8 border-gym-800 flex flex-col items-center justify-center transition-all duration-300`}>
                <p className="text-[10px] text-gray-500 uppercase font-bold mb-1">Rep Progress</p>
                <h2 className="text-7xl font-black text-white tabular-nums">
                  {Math.round(progress * 100)}<span className="text-2xl text-gym-accent">%</span>
                </h2>
                <div className="mt-4 px-4 py-1 bg-gym-900 border border-gym-700 rounded-full text-xs font-bold text-gray-300">
                  {phase.replace('_', ' ')}
                </div>
              </div>

              {/* Progress Ring (SVG) */}
              <svg className="absolute top-0 left-0 w-72 h-72 -rotate-90 pointer-events-none">
                <circle 
                  cx="144" cy="144" r="136" 
                  stroke="currentColor" strokeWidth="12" 
                  fill="transparent"
                  strokeLinecap="round"
                  strokeDasharray={854} 
                  strokeDashoffset={854 - (854 * progress)}
                  className={`transition-all duration-75 text-gym-accent`}
                />
              </svg>
            </div>

            <div className="mt-12 flex items-center gap-8">
               <button 
                 onClick={() => setIsPaused(!isPaused)}
                 className={`w-20 h-20 rounded-full flex items-center justify-center border-2 ${isPaused ? 'bg-gym-success border-white' : 'bg-gym-800 border-gym-700'} text-white shadow-xl transition-all`}
               >
                 {isPaused ? <Play size={32} fill="currentColor" /> : <Pause size={32} fill="currentColor" />}
               </button>
            </div>
          </>
        )}
      </div>

      {/* FOOTER */}
      <div className="p-6 bg-gym-800 border-t border-gym-700 flex justify-between items-center z-10">
        <div>
          <p className="text-[10px] text-gray-500 uppercase font-bold tracking-wider">Lifting Guard</p>
          <p className="text-5xl font-black text-white leading-none">
            {reps} <span className="text-xl text-gray-500 font-medium">/ {targetReps}</span>
          </p>
        </div>
        <button 
          onClick={onClose}
          className="px-8 py-4 bg-white text-gym-900 font-black rounded-2xl shadow-xl active:scale-95 transition-transform"
        >
          FINISH SET
        </button>
      </div>
    </div>
  );
};

export default MotionTracker;

import { Exercise, MotionType } from '../types';

export type Position = 'POCKET' | 'HAND' | 'CHEST';
export type MotionPhase = 'IDLE' | 'ECCENTRIC' | 'BOTTOM_HOLD' | 'CONCENTRIC' | 'TOP_HOLD' | 'CALIB_COUNTDOWN' | 'CALIB_RECORDING';
export type FeedbackType = 'PERFECT' | 'TOO_FAST' | 'TOO_SLOW' | 'GOOD' | 'WARNING';

export interface TempoConfig {
  eccentric: number; // Seconds down
  bottom: number;    // Seconds hold
  concentric: number;// Seconds up
  top: number;       // Seconds reset
}

export interface MotionEvent {
  phase: MotionPhase;
  progress: number; // 0.0 (Start) to 1.0 (End/Deep)
  targetProgress: number; // Where they SHOULD be (for Game Pacer)
  repCount: number;
  feedback?: string;
  feedbackType?: FeedbackType;
  rawDebug?: string;
}

export class MotionProcessor {
  // Configuration
  private position: Position;
  private tempo: TempoConfig;
  private motionType: MotionType;
  private exerciseName: string;

  // State
  private currentPhase: MotionPhase = 'IDLE';
  private lastPhaseChangeTime: number = 0;
  private repCount: number = 0;
  private repStartTime: number = 0;

  // Rep Logic
  private hasReachedBottom: boolean = false;
  private hasReachedTop: boolean = false;

  // Calibration (Range of Motion)
  private minRawValue: number = Infinity;
  private maxRawValue: number = -Infinity;
  private calibratedMin: number = 0;
  private calibratedMax: number = 0;
  private isCalibrated: boolean = false;
  private calibrationDirection: 'NORMAL' | 'INVERTED' = 'NORMAL'; // Normal = Increasing Value goes DOWN

  // Smoothing
  private lastSmoothedValue: number = 0;
  private velocity: number = 0; 
  private smoothingFactor: number = 0.15; // Increased smoothing

  // Fatigue Management
  private fatigueFactor: number = 0; // Increases by 0.05 per rep

  // Callbacks
  private onUpdate: (event: MotionEvent) => void;

  constructor(
    exercise: Exercise, 
    position: Position, 
    onUpdate: (event: MotionEvent) => void
  ) {
    this.exerciseName = exercise.name.toLowerCase();
    this.motionType = exercise.motionType || 'press';
    this.position = position;
    this.onUpdate = onUpdate;

    // Parse Tempo
    const phases = exercise.pacer.phases;
    this.tempo = {
      eccentric: phases.find(p => ['LOWER', 'DOWN', 'OPEN'].some(k => p.action.includes(k)))?.duration || 3,
      bottom: phases.find(p => ['STRETCH', 'HOLD', 'BOTTOM'].some(k => p.action.includes(k)))?.duration || 1,
      concentric: phases.find(p => ['PRESS', 'PULL', 'UP', 'DRIVE', 'CURL'].some(k => p.action.includes(k)))?.duration || 1.5,
      top: 1
    };
  }

  public process(alpha: number | null, beta: number | null, gamma: number | null) {
    if (alpha === null || beta === null || gamma === null) return;

    // 1. Get Axis
    const rawValue = this.getRelevantAxisValue(beta, gamma);

    // 2. Smoothing
    const smoothedValue = this.lastSmoothedValue + this.smoothingFactor * (rawValue - this.lastSmoothedValue);
    this.velocity = smoothedValue - this.lastSmoothedValue;
    this.lastSmoothedValue = smoothedValue;

    // 3. Logic Branch
    if (this.currentPhase === 'CALIB_RECORDING') {
      this.handleCalibrationRecording(smoothedValue);
    } else if (this.currentPhase !== 'CALIB_COUNTDOWN') {
      this.handleWorkoutLoop(smoothedValue);
    }
  }

  public startCalibrationCountdown() {
    this.currentPhase = 'CALIB_COUNTDOWN';
    this.repCount = 0;
    // Emit initial event to UI
    this.emitState(0, "Get Ready...", 'WARNING');
  }

  public startCalibrationRecording() {
    this.currentPhase = 'CALIB_RECORDING';
    this.minRawValue = Infinity;
    this.maxRawValue = -Infinity;
    // Reset ROM
    this.emitState(0, this.getStartCue(), 'WARNING');
  }

  public finishCalibration() {
    // Add buffer
    const range = this.maxRawValue - this.minRawValue;
    if (range < 10) {
        // Did not move enough
        this.emitState(0, "Movement too small. Try again.", "WARNING");
        return false;
    }

    // Determine Direction automatically
    // If we assume user starts at TOP/START position
    // For Squat (Pocket): Stand (90) -> Sit (0). Value Decreases.
    // For Curl (Hand): Hang (-90) -> Curl (45). Value Increases.

    // We define: Progress 0 = Start Position, Progress 1 = Max Stretch/Contraction
    // Logic: If the LAST recorded value is closer to MAX, then Start must be MIN (Normal).
    // If LAST recorded value is closer to MIN, then Start must be MAX (Inverted).
    // Actually, simple heuristic:
    // Pocket/Squat: Decreasing = Down.
    // Hand/Curl: Increasing = Up.

    if (this.position === 'POCKET') {
        this.calibrationDirection = 'INVERTED'; // 90(Start) -> 0(End)
    } else {
        this.calibrationDirection = 'NORMAL'; // -90(Start) -> 90(End)
    }

    this.calibratedMin = this.minRawValue;
    this.calibratedMax = this.maxRawValue;
    this.isCalibrated = true;
    this.currentPhase = 'IDLE';
    this.hasReachedBottom = false;
    this.hasReachedTop = true;
    this.emitState(0, "Ready. Go!", "GOOD");
    return true;
  }

  private getRelevantAxisValue(beta: number, gamma: number): number {
    // Pocket: Beta (Tilt forward/back)
    if (this.position === 'POCKET') return beta;
    // Hand: Beta (Tilt of phone in hand)
    return beta; 
  }

  private getNormalizedProgress(rawValue: number): number {
    if (!this.isCalibrated) return 0;

    const clamped = Math.max(Math.min(rawValue, this.maxRawValue), this.minRawValue);
    let pct = (clamped - this.calibratedMin) / (this.calibratedMax - this.calibratedMin);

    if (this.calibrationDirection === 'INVERTED') {
        return 1 - pct;
    }
    return pct;
  }

  private handleCalibrationRecording(val: number) {
    if (val < this.minRawValue) this.minRawValue = val;
    if (val > this.maxRawValue) this.maxRawValue = val;

    // Visualize raw movement range
    // Since we don't know min/max yet, we just jitter or show raw
    this.emitState(0.5, "Move full range...", 'WARNING');
  }

  private handleWorkoutLoop(rawValue: number) {
    const progress = this.getNormalizedProgress(rawValue);
    const now = Date.now();
    const phaseDuration = (now - this.lastPhaseChangeTime) / 1000;

    // --- FATIGUE COMPENSATION ---
    // As reps increase, we allow slightly slower times without penalty
    // Factor: +5% allowed time per rep after rep 5
    const fatigueMultiplier = this.repCount > 5 ? 1 + ((this.repCount - 5) * 0.05) : 1.0;

    let targetProgress = 0; // For Ghost Pacer

    // --- STATE MACHINE ---
    switch (this.currentPhase) {
      case 'IDLE':
      case 'TOP_HOLD':
        targetProgress = 0;
        // Start Eccentric if we move past 15% ROM
        if (progress > 0.15) {
          this.transitionTo('ECCENTRIC');
          this.hasReachedBottom = false;
        }
        break;

      case 'ECCENTRIC':
        // Moving 0 -> 1
        // Calculate Target Pacer Progress (Linear 0 to 1 over eccentric time)
        targetProgress = Math.min(1, phaseDuration / (this.tempo.eccentric * fatigueMultiplier));

        // Speed Check
        if (targetProgress < progress - 0.2) {
             // You are ahead of target (Too Fast)
             this.emitState(progress, "Too Fast! Resist.", 'TOO_FAST');
        } else {
             this.emitState(progress, this.getEccentricCue(), 'PERFECT');
        }

        // Transition
        if (progress > 0.85) {
          this.hasReachedBottom = true;
          this.transitionTo('BOTTOM_HOLD');
        }
        break;

      case 'BOTTOM_HOLD':
        targetProgress = 1;
        // Holding at 1
        const requiredHold = this.tempo.bottom;

        if (progress < 0.80) {
            // Moved up early?
            if (phaseDuration < requiredHold * 0.5) {
                // Bounced
                this.emitState(progress, "Don't Bounce!", 'TOO_FAST');
                this.transitionTo('CONCENTRIC');
            } else {
                this.transitionTo('CONCENTRIC');
            }
        } else {
            // Still holding
            if (phaseDuration > requiredHold + 1.0) {
                 this.emitState(progress, "Power Up Now!", 'TOO_SLOW');
            } else {
                 this.emitState(progress, "Hold...", 'PERFECT');
            }
        }
        break;

      case 'CONCENTRIC':
        // Moving 1 -> 0
        targetProgress = Math.max(0, 1 - (phaseDuration / (this.tempo.concentric * fatigueMultiplier)));

        // Guidance
        this.emitState(progress, this.getConcentricCue(), 'PERFECT');

        // Transition
        if (progress < 0.15) {
            if (this.hasReachedBottom) {
                this.repCount++;
                this.hasReachedBottom = false;
                this.transitionTo('TOP_HOLD', { type: 'GOOD', msg: `${this.repCount} Reps` });
            } else {
                // False rep (didn't hit bottom)
                this.transitionTo('IDLE');
            }
        }
        break;
    }

    // Add computed target to event for Game Mode
    this.lastEvent = {
        ...this.lastEvent,
        progress,
        targetProgress
    };
    this.onUpdate(this.lastEvent);
  }

  private lastEvent: MotionEvent = { phase: 'IDLE', progress: 0, targetProgress: 0, repCount: 0 };

  private transitionTo(newPhase: MotionPhase, feedback?: { type: FeedbackType; msg: string }) {
    this.currentPhase = newPhase;
    this.lastPhaseChangeTime = Date.now();
    if (feedback) {
        this.emitState(0, feedback.msg, feedback.type); // progress gets overwritten in loop
    }
  }

  private emitState(progress: number, feedbackMsg?: string, feedbackType?: FeedbackType) {
    this.lastEvent = {
      phase: this.currentPhase,
      progress,
      targetProgress: 0, // Calculated in loop
      repCount: this.repCount,
      feedback: feedbackMsg,
      feedbackType
    };
    this.onUpdate(this.lastEvent);
  }

  // --- CUE GENERATORS ---
  private getStartCue() {
      if (this.motionType === 'press' || this.motionType === 'squat') return "Start at TOP (Lockout)";
      if (this.motionType === 'pull' || this.motionType === 'curl') return "Start at BOTTOM (Hang)";
      return "Start at Resting Pos";
  }

  private getEccentricCue() {
      if (this.motionType === 'press') return "Control Down...";
      if (this.motionType === 'squat') return "Sit Back Slow...";
      if (this.motionType === 'pull' || this.motionType === 'curl') return "Release Slowly...";
      return "Slow...";
  }

  private getConcentricCue() {
      if (this.motionType === 'press') return "DRIVE UP!";
      if (this.motionType === 'squat') return "PUSH FLOOR!";
      if (this.motionType === 'pull') return "PULL HARD!";
      if (this.motionType === 'curl') return "SQUEEZE UP!";
      return "Power!";
  }
}

import React, { useRef, useEffect } from 'react';
import { PacerConfig } from '../types';

interface Props {
  progress: number; // 0 to 1
  phase: string;
  isPaused: boolean;
  pacerConfig: PacerConfig;
}

const GamePacer: React.FC<Props> = ({ progress, phase, isPaused, pacerConfig }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const scrollRef = useRef(0);

  // Calculate ideal path based on tempo
  // We need to map time -> ideal progress (0 to 1)
  const getIdealProgress = (time: number) => {
      const totalDur = pacerConfig.phases.reduce((acc, p) => acc + p.duration, 0) * 1000;
      const t = time % totalDur;
      let elapsed = 0;

      for (const p of pacerConfig.phases) {
          const dur = p.duration * 1000;
          if (t < elapsed + dur) {
              const localT = (t - elapsed) / dur;
              const action = p.action.toUpperCase();

              // 0=Top/Start, 1=Bottom/Deep
              // Eccentric (Down): 0 -> 1
              if (['LOWER', 'DOWN', 'SIT'].some(k => action.includes(k))) return localT;

              // Concentric (Up): 1 -> 0
              if (['UP', 'PRESS', 'DRIVE', 'PULL', 'CURL'].some(k => action.includes(k))) return 1 - localT;

              // Holds
              if (['STRETCH', 'BOTTOM'].some(k => action.includes(k))) return 1;
              return 0;
          }
          elapsed += dur;
      }
      return 0;
  };

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let animId: number;
    const startTime = Date.now();

    const draw = () => {
      if (!canvas) return;
      const width = canvas.width;
      const height = canvas.height;
      const now = Date.now();

      if (!isPaused) {
          scrollRef.current += 2; // Speed of scroll
      }

      // Clear
      ctx.fillStyle = '#1e293b'; // Gym-800
      ctx.fillRect(0, 0, width, height);

      // Draw Tunnel (The Path)
      ctx.beginPath();
      ctx.lineWidth = 40; // Tunnel width
      ctx.lineCap = 'round';
      ctx.lineJoin = 'round';
      ctx.strokeStyle = '#334155'; // Gym-700

      // Draw future path points
      const pointsToDraw = 50; // How far ahead
      const spacing = 10;

      for (let i = 0; i < pointsToDraw; i++) {
          const futureTime = now + (i * 100); // look ahead time
          const idealP = getIdealProgress(futureTime);

          // Map progress 0-1 to Height
          // 0 = Top of Screen (10% padding), 1 = Bottom (90% padding)
          const y = (height * 0.1) + (idealP * (height * 0.8));
          const x = (width * 0.2) + (i * spacing); // Player is at 20% width

          if (i === 0) ctx.moveTo(x, y);
          else ctx.lineTo(x, y);
      }
      ctx.stroke();

      // Draw Target (Ghost)
      const currentTargetP = getIdealProgress(now);
      const targetY = (height * 0.1) + (currentTargetP * (height * 0.8));
      const playerX = width * 0.2;

      ctx.fillStyle = 'rgba(59, 130, 246, 0.3)'; // Blue ghost
      ctx.beginPath();
      ctx.arc(playerX, targetY, 15, 0, Math.PI * 2);
      ctx.fill();

      // Draw Player
      const playerY = (height * 0.1) + (progress * (height * 0.8));

      // Determine color based on error
      const diff = Math.abs(playerY - targetY);
      let playerColor = '#4ade80'; // Green
      if (diff > 40) playerColor = '#ef4444'; // Red (Fail)
      else if (diff > 20) playerColor = '#facc15'; // Yellow (Warning)

      ctx.fillStyle = playerColor;
      ctx.shadowBlur = 10;
      ctx.shadowColor = playerColor;
      ctx.beginPath();
      ctx.arc(playerX, playerY, 10, 0, Math.PI * 2);
      ctx.fill();
      ctx.shadowBlur = 0;

      // Labels
      ctx.fillStyle = '#94a3b8';
      ctx.font = '10px monospace';
      ctx.fillText("TOP / START", 5, 15);
      ctx.fillText("BOTTOM / DEEP", 5, height - 5);

      animId = requestAnimationFrame(draw);
    };

    draw();
    return () => cancelAnimationFrame(animId);
  }, [progress, isPaused, pacerConfig]);

  return (
    <div className="relative w-full h-64 rounded-xl overflow-hidden border border-gym-600 shadow-inner">
       <canvas ref={canvasRef} width={350} height={256} className="w-full h-full" />
       {/* Overlay Text */}
       <div className="absolute top-2 right-2 text-xs font-bold text-white bg-black/50 px-2 py-1 rounded">
           GAME MODE
       </div>
    </div>
  );
};

