  // Smoothing
  private lastSmoothedValue: number = 0;
  private smoothingFactor: number = 0.15; 
  private velocity: number = 0;

  // Fatigue Management
  private fatigueFactor: number = 0; 

  // Callbacks
  private onUpdate: (event: MotionEvent) => void;
  private manualInterval: any = null;

  constructor(
    exercise: Exercise, 
