    // Don't reset min/max here if we want to support re-calibration refinement
    // But for a hard reset calibration:
    this.minRawValue = Infinity;
    this.maxRawValue = -Infinity;

    const moveMsg = this.startsAtTop
        ? "Lower slowly... then Press up"
        : "Lift up... then Lower slowly";

    this.emitState(this.startsAtTop ? 0 : 1, moveMsg, 'WARNING');
  }

  public finishCalibration(): boolean {
    const range = this.maxRawValue - this.minRawValue;
    if (range < 5) { // Very permissive threshold
        this.emitState(0, "Movement too small. Try again.", "WARNING");
        return false;
    }

    // Determine Direction automatically based on sensor heuristic
    if (this.position === 'POCKET') {
        this.calibrationDirection = 'INVERTED'; 
    } else {
        this.calibrationDirection = 'NORMAL'; 
    }

    this.calibratedMin = this.minRawValue;
    this.calibratedMax = this.maxRawValue;
    this.isCalibrated = true;
    this.currentPhase = 'IDLE';
    this.emitState(this.startsAtTop ? 0 : 1, "Ready. Go!", "GOOD");
    return true;
  }

  public process(alpha: number | null, beta: number | null, gamma: number | null) {
    if (this.isManualMode) return;
    if (alpha === null || beta === null || gamma === null) return;

    // 1. Get Axis
    const rawValue = this.getRelevantAxisValue(beta, gamma);

    // 2. Smoothing
    const smoothedValue = this.lastSmoothedValue + this.smoothingFactor * (rawValue - this.lastSmoothedValue);
    this.velocity = smoothedValue - this.lastSmoothedValue;
    this.lastSmoothedValue = smoothedValue;

    // 3. Update Running Min/Max (ML Learning during set)
    // We allow the range to expand slightly if user goes deeper
    if (this.currentPhase !== 'CALIB_COUNTDOWN') {
        if (smoothedValue < this.minRawValue) this.minRawValue = smoothedValue;
        if (smoothedValue > this.maxRawValue) this.maxRawValue = smoothedValue;

        // Dynamic Adaptation: If saved calibration was too small, expand it on the fly
        if (this.isCalibrated) {
             if (smoothedValue < this.calibratedMin) this.calibratedMin = smoothedValue;
             if (smoothedValue > this.calibratedMax) this.calibratedMax = smoothedValue;
        }
    }

    // 4. Logic Branch
    if (this.currentPhase === 'CALIB_RECORDING') {
      // Just track min/max (handled above)
      this.emitState(0.5, "Move full range...", 'WARNING');
    } else if (this.currentPhase !== 'CALIB_COUNTDOWN') {
      this.handleWorkoutLoop(smoothedValue);
    }
  }

  // --- INTERNAL LOGIC ---

  private getRelevantAxisValue(beta: number, gamma: number): number {
    return beta; // Beta (Tilt) is almost always the primary driver for gym motions
  }

  private getNormalizedProgress(rawValue: number): number {
    if (!this.isCalibrated) return 0;

    const clamped = Math.max(Math.min(rawValue, this.calibratedMax), this.calibratedMin);
    let pct = (clamped - this.calibratedMin) / (this.calibratedMax - this.calibratedMin);

    if (this.calibrationDirection === 'INVERTED') {
        return 1 - pct;
    }
    return pct;
  }

  private startManualLoop() {
      // Manual Mode: Simulate a perfect rep loop based on tempo
      this.currentPhase = 'IDLE';
      this.transitionTo(this.startsAtTop ? 'ECCENTRIC' : 'CONCENTRIC');

      let startTime = Date.now();

      this.manualInterval = setInterval(() => {
          const now = Date.now();
          const phaseDuration = (now - this.lastPhaseChangeTime) / 1000;
          let progress = 0;
          let targetProgress = 0;

          // Simple State Machine for Manual
          switch(this.currentPhase) {
              case 'ECCENTRIC':
                  progress = Math.min(1, phaseDuration / this.tempo.eccentric);
                  targetProgress = progress;
                  if (progress >= 1) this.transitionTo('BOTTOM_HOLD');
                  break;
              case 'BOTTOM_HOLD':
                  progress = 1;
                  targetProgress = 1;
                  if (phaseDuration >= this.tempo.bottom) this.transitionTo('CONCENTRIC');
                  break;
              case 'CONCENTRIC':
                  progress = Math.max(0, 1 - (phaseDuration / this.tempo.concentric));
                  targetProgress = progress;
                  if (progress <= 0) {
                      this.repCount++;
                      this.transitionTo('TOP_HOLD', { type: 'GOOD', msg: `${this.repCount}` });
                  }
                  break;
              case 'TOP_HOLD':
                  progress = 0;
                  targetProgress = 0;
                  if (phaseDuration >= this.tempo.top) this.transitionTo('ECCENTRIC');
                  break;
          }

          // For Manual mode, progress 0->1 matches Standard.
          // For Inverted (Curl), we need to flip it for the logic to match "Visual" consistency if we reused logic.
          // But here we construct progress manually.
          // Let's assume Manual Loop simulates Standard 0->1.
          // And emitState will handle visual inversion for !startsAtTop.
          // Wait, if !startsAtTop (Curl), logic below expects 0->1 for Concentric.
          // Manual loop above simulates Standard (Eccentric first).
          // We need Manual Loop for Curl too.

          if (!this.startsAtTop) {
              // Invert for Curl logic (Concentric first)
              // Actually, simpler to just use standard progress and let emitState flip it if needed?
              // No, emitState flips based on exercise type.
              // Let's just emit raw 0..1 from here and let emitState handle visual mapping.
          }

          this.emitState(progress, this.getPhaseCue(this.currentPhase), 'PERFECT');
      }, 50);
  }

  private handleWorkoutLoop(rawValue: number) {
    const progress = this.getNormalizedProgress(rawValue);
    const now = Date.now();
    const phaseDuration = (now - this.lastPhaseChangeTime) / 1000;
    const fatigueMultiplier = this.repCount > 5 ? 1 + ((this.repCount - 5) * 0.05) : 1.0;

    if (this.startsAtTop) {
        this.handleStandardLoop(progress, phaseDuration, fatigueMultiplier);
    } else {
        this.handleInvertedLoop(progress, phaseDuration, fatigueMultiplier);
    }
  }

  private handleStandardLoop(progress: number, phaseDuration: number, fatigue: number) {
      // 0 = Top, 1 = Bottom
      switch (this.currentPhase) {
          case 'IDLE':
          case 'TOP_HOLD':
            if (progress > 0.15) this.transitionTo('ECCENTRIC');
            break;
          case 'ECCENTRIC': // Going 0 -> 1
            const target = Math.min(1, phaseDuration / (this.tempo.eccentric * fatigue));
            this.checkSpeed(progress, target, 0.2);
            if (progress > 0.85) this.transitionTo('BOTTOM_HOLD');
            break;
          case 'BOTTOM_HOLD': // Holding at 1
            if (progress < 0.80 && phaseDuration > 0.5) this.transitionTo('CONCENTRIC');
            break;
          case 'CONCENTRIC': // Going 1 -> 0
            if (progress < 0.15) {
                this.repCount++;
                this.transitionTo('TOP_HOLD', { type: 'GOOD', msg: `${this.repCount}` });
            }
            break;
      }
      this.emitState(progress, this.getPhaseCue(this.currentPhase), this.lastEvent.feedbackType);
  }

  private handleInvertedLoop(progress: number, phaseDuration: number, fatigue: number) {
      // INTERNAL LOGIC: 0 = Start (Bottom), 1 = End (Top)
      switch (this.currentPhase) {
          case 'IDLE':
          case 'TOP_HOLD': // Actually Start/Bottom Position
             if (progress > 0.15) this.transitionTo('CONCENTRIC');
             break;
          case 'CONCENTRIC': // Going 0 -> 1 (Lifting)
             const target = Math.min(1, phaseDuration / (this.tempo.concentric * fatigue));
             // Don't penalize fast concentric usually
             if (progress > 0.85) this.transitionTo('BOTTOM_HOLD'); // Peak Hold
             break;
          case 'BOTTOM_HOLD': // Holding at 1 (Peak)
             if (progress < 0.80 && phaseDuration > 0.5) this.transitionTo('ECCENTRIC');
             break;
          case 'ECCENTRIC': // Going 1 -> 0 (Lowering)
             const eccTarget = Math.max(0, 1 - (phaseDuration / (this.tempo.eccentric * fatigue)));
             // Speed check: If progress (real) is lower than target, we dropped too fast
             // (Since 1 is Peak, 0 is Bottom. Lower means closer to 0)
             if (progress < eccTarget - 0.2) this.lastEvent.feedbackType = 'TOO_FAST';
             else this.lastEvent.feedbackType = 'PERFECT';

             if (progress < 0.15) {
                 this.repCount++;
                 this.transitionTo('TOP_HOLD', { type: 'GOOD', msg: `${this.repCount}` });
             }
             break;
      }
      this.emitState(progress, this.getPhaseCue(this.currentPhase), this.lastEvent.feedbackType);
  }

  private checkSpeed(actual: number, target: number, tol: number) {
      // Standard: target increases 0->1. If actual > target + tol, Too Fast.
      if (actual > target + tol) this.lastEvent.feedbackType = 'TOO_FAST';
      else this.lastEvent.feedbackType = 'PERFECT';
  }

  private lastEvent: MotionEvent = { phase: 'IDLE', progress: 0, targetProgress: 0, repCount: 0 };

  private transitionTo(newPhase: MotionPhase, feedback?: { type: FeedbackType; msg: string }) {
    this.currentPhase = newPhase;
    this.lastPhaseChangeTime = Date.now();
    if (feedback) {
        // Use current raw progress for transition event
        const rawP = this.lastEvent.progress; 
        // We need to pass the *internal* progress to emitState to let it normalize
        // But emitState takes "progress" argument.
        // Quick fix: just re-emit last known progress.
        // Actually, better to just let the loop handle the next emit.
        // We just update the feedback here.
        this.lastEvent.feedback = feedback.msg;
        this.lastEvent.feedbackType = feedback.type;
        this.onUpdate({...this.lastEvent, phase: newPhase});
    }
  }

  private emitState(internalProgress: number, feedbackMsg?: string, feedbackType?: FeedbackType) {
    // VISUAL NORMALIZATION:
    // We want 0 to always be "Top/Extended/Start of Gravity" and 1 to be "Bottom/Flexed/End of Gravity".
    // For Standard (Bench): Start(0) -> End(1). Matches Internal (0->1).
    // For Inverted (Curl): Start(0) is Bottom. End(1) is Top.
    // To match GamePacer (which draws 0 at Top, 1 at Bottom):
    // Curl Start (Bottom) should be 1. Curl Peak (Top) should be 0.
    // So for Inverted, we flip: Visual = 1 - Internal.

    const visualProgress = this.startsAtTop ? internalProgress : (1 - internalProgress);

    this.lastEvent = {
      phase: this.currentPhase,
      progress: visualProgress,
      targetProgress: 0, 
      repCount: this.repCount,
      feedback: feedbackMsg,
      feedbackType: feedbackType || this.lastEvent.feedbackType,
      debug: `Raw: ${this.lastSmoothedValue.toFixed(0)}`
    };
    this.onUpdate(this.lastEvent);
  }

  private getPhaseCue(phase: MotionPhase): string {
      switch(phase) {
          case 'ECCENTRIC': return "Control Down...";
          case 'CONCENTRIC': return "Power!";
          case 'BOTTOM_HOLD': return "Hold...";
          case 'TOP_HOLD': return "Reset";
          default: return "";
      }
  }
}

import React, { useState, useEffect, useRef } from 'react';
import { X, Play, Pause, Volume2, VolumeX, Smartphone, Waves, Target, CheckCircle2, AlertTriangle, Gamepad2, Activity, ZapOff, CheckCircle } from 'lucide-react';
import { Exercise } from '../types';
import { MotionProcessor, Position, MotionEvent } from '../services/MotionProcessor';
import { getCalibration, saveCalibration } from '../services/storageService';
import GamePacer from './GamePacer';

interface Props {
  exercise: Exercise;
  onRepCount: (count: number) => void;
  onClose: () => void;
  targetReps: number;
}

const MotionTracker: React.FC<Props> = ({ exercise, onRepCount, onClose, targetReps }) => {
  // --- STATE ---
  const [isPaused, setIsPaused] = useState(false);
  const [reps, setReps] = useState(0);
  const [processorEvent, setProcessorEvent] = useState<MotionEvent | null>(null);

  // Settings
  const [isMuted, setIsMuted] = useState(false);
  const [isVibrationOff, setIsVibrationOff] = useState(false);
  const [isManualMode, setIsManualMode] = useState(false);
  const [permissionState, setPermissionState] = useState<'prompt' | 'granted' | 'denied'>('prompt');

  // Calibration States
  const [calibState, setCalibState] = useState<'NONE' | 'COUNTDOWN' | 'RECORDING' | 'DONE'>('NONE');
  const [calibCount, setCalibCount] = useState(3);

  // Modes
  const [mode, setMode] = useState<'STANDARD' | 'GAME'>('STANDARD');

  // --- REFS ---
  const synthRef = useRef<SpeechSynthesis | null>(null);
  const processorRef = useRef<MotionProcessor | null>(null);
  const isMutedRef = useRef(false);
  const isVibrationOffRef = useRef(false);
  const isMountedRef = useRef(true);
  const modeRef = useRef('STANDARD');

  // --- INIT ---
  useEffect(() => {
    isMountedRef.current = true;
    if ('speechSynthesis' in window) synthRef.current = window.speechSynthesis;

    // Auto-detect existing calibration
    const savedCal = getCalibration(exercise.id);
    if (savedCal) {
        setCalibState('DONE'); // Skip calibration if known
    }

    return () => {
        isMountedRef.current = false;
        cleanup();
    };
  }, []);

  // Update refs when state changes for access inside callbacks
  useEffect(() => {
      isMutedRef.current = isMuted;
      isVibrationOffRef.current = isVibrationOff;
      modeRef.current = mode;
  }, [isMuted, isVibrationOff, mode]);

  const cleanup = () => {
      if (synthRef.current) {
          synthRef.current.cancel();
      }
      if (processorRef.current) {
          processorRef.current.cleanup();
          processorRef.current = null;
      }
      window.removeEventListener('deviceorientation', handleOrientation);
  };

  const handleOrientation = (event: DeviceOrientationEvent) => {
    if (processorRef.current && !isPaused && !isManualMode && isMountedRef.current) {
      processorRef.current.process(event.alpha, event.beta, event.gamma);
    }
  };

  const requestPermission = async () => {
    if (typeof (DeviceOrientationEvent as any).requestPermission === 'function') {
      try {
        const response = await (DeviceOrientationEvent as any).requestPermission();
        if (response === 'granted') {
          setPermissionState('granted');
          initProcessor(false);
        } else {
          setPermissionState('denied');
          // Auto fallback to manual mode if denied
          setIsManualMode(true);
          initProcessor(true);
        }
      } catch (e) {
        console.error(e);
        // Fallback
        setIsManualMode(true);
        initProcessor(true);
      }
    } else {
      setPermissionState('granted');
      initProcessor(false);
    }
  };

  const initProcessor = (manual: boolean) => {
    const savedCal = getCalibration(exercise.id);

    processorRef.current = new MotionProcessor(
      exercise,
      (event) => {
        if (!isMountedRef.current) return;

        setProcessorEvent(event);

        // Voice Feedback
        if (event.feedback && event.feedbackType !== 'WARNING') {
             speak(event.feedback);
        }

        if (event.repCount > reps) {
          setReps(event.repCount);
          onRepCount(event.repCount);
          speak(String(event.repCount));

          // In GAME mode, only vibrate on mistakes, not successes
          if (modeRef.current === 'STANDARD') {
              triggerHaptic([50, 50]);
          }
        }

        // Feedback vibration (Mistakes) - Always allowed in both modes
        if (event.feedbackType === 'TOO_FAST' || event.feedbackType === 'TOO_SLOW') {
            triggerHaptic([200]);
        }
      },
      savedCal
    );

    if (manual) {
        setCalibState('DONE'); // No calibration needed for manual
        processorRef.current.setManualMode(true);
    } else {
        window.addEventListener('deviceorientation', handleOrientation);
    }
  };

  const handleManualStart = () => {
      setIsManualMode(true);
      setPermissionState('granted'); // Bypass screen
      initProcessor(true);
  };

  // --- CALIBRATION LOGIC ---
  const startCalibrationSequence = () => {
      setCalibState('COUNTDOWN');
      setCalibCount(3);
      if (processorRef.current) processorRef.current.startCalibrationCountdown();

      const int = setInterval(() => {
          if (!isMountedRef.current) {
              clearInterval(int);
              return;
          }
          setCalibCount(prev => {
              if (prev <= 1) {
                  clearInterval(int);
                  beginRecording();
                  return 0;
              }
              speak(String(prev - 1));
              return prev - 1;
          });
      }, 1000);
      speak("3");
  };

  const beginRecording = () => {
      setCalibState('RECORDING');
      if (processorRef.current) processorRef.current.startCalibrationRecording();
  };

  const finishCalibration = () => {
      if (processorRef.current) {
          const success = processorRef.current.finishCalibration();
          if (success) {
              setCalibState('DONE');
              speak("Calibrated.");

              // Save Calibration Data
              const calData = processorRef.current.getCalibrationData();
              calData.exerciseId = exercise.id;
              saveCalibration(calData);
          } else {
              setCalibState('NONE'); // Retry
              speak("Retry.");
          }
      }
  };

  const resetCalibration = () => {
      setCalibState('NONE');
  };

  // --- AUDIO & HAPTICS ---
  const speak = (text: string) => {
    if (isMutedRef.current || !synthRef.current || !isMountedRef.current) return;
    if (synthRef.current.speaking) return; 

    const u = new SpeechSynthesisUtterance(text);
    u.rate = 1.1; 
    synthRef.current.speak(u);
  };

  const triggerHaptic = (pattern: number[]) => {
    if (isVibrationOffRef.current || !navigator.vibrate || !isMountedRef.current) return;
    navigator.vibrate(pattern);
  };

  const handleClose = () => {
      cleanup();
      onClose();
  };

  // --- RENDER HELPERS ---
  const progress = processorEvent?.progress || 0;
  const phase = processorEvent?.phase || 'IDLE';
  const feedbackMsg = processorEvent?.feedback;
  const targetPos = exercise.targetGroup === 'Legs' ? 'Pocket' : 'Armband / Hand';

  // -- PERMISSION SCREEN --
  if (permissionState === 'prompt' && !isManualMode) {
    return (
      <div className="fixed inset-0 z-[60] bg-gym-900 flex flex-col items-center justify-center p-8 text-center animate-in fade-in">
        <Smartphone size={64} className="text-gym-accent mb-6 animate-bounce" />
        <h2 className="text-3xl font-black text-white mb-4">Motion Guard</h2>

        <div className="bg-gym-800 p-4 rounded-xl border border-gym-700 mb-6 text-left w-full">
            <p className="text-xs text-gray-400 font-bold uppercase mb-2">Instructions</p>
            <ul className="text-sm text-gray-300 space-y-2 list-disc list-inside">
                <li>Mount phone: <strong>{targetPos}</strong></li>
                <li>We track your <strong>Tempo</strong> & <strong>ROM</strong>.</li>
                <li>Keeps you honest on reps.</li>
            </ul>
        </div>

        <button onClick={requestPermission} className="w-full py-5 bg-white text-gym-900 font-black rounded-2xl shadow-xl mb-4">START SENSORS</button>
        <button onClick={handleManualStart} className="text-gray-500 font-bold hover:text-white">Use Visual Pacer (No Sensors)</button>
        <button onClick={onClose} className="mt-6 text-gray-500 text-xs">Cancel</button>
      </div>
    );
  }

  return (
    <div className="fixed inset-0 z-[60] bg-gym-900 flex flex-col animate-in fade-in duration-300">
      {/* HEADER */}
      <div className="p-4 flex justify-between items-center border-b border-gym-700 bg-gym-800">
        <div>
          <h3 className="font-bold text-white text-lg">{exercise.name}</h3>
          <p className="text-xs text-gym-accent flex items-center gap-1">
              {isManualMode ? 'Visual Timer Mode' : 'Sensor Active'} 
              {isManualMode && <Activity size={10}/>}
          </p>
        </div>
        <div className="flex gap-2">
          <button onClick={() => setMode(mode === 'GAME' ? 'STANDARD' : 'GAME')} className="p-2 bg-gym-700 rounded-full text-white">{mode === 'GAME' ? <Activity size={20}/> : <Gamepad2 size={20}/>}</button>

          <button onClick={() => setIsVibrationOff(!isVibrationOff)} className={`p-2 rounded-full ${isVibrationOff ? 'text-gray-500 bg-gym-800' : 'text-white bg-gym-700'}`}>
              {isVibrationOff ? <ZapOff size={20}/> : <Waves size={20}/>}
          </button>

          <button onClick={() => setIsMuted(!isMuted)} className={`p-2 rounded-full ${isMuted ? 'text-gray-500 bg-gym-800' : 'text-white bg-gym-700'}`}>
              {isMuted ? <VolumeX size={20}/> : <Volume2 size={20}/>}
          </button>

          <button onClick={handleClose} className="p-2 bg-gym-700 rounded-full text-white"><X size={20}/></button>
        </div>
      </div>

      {/* MAIN VIEW */}
      <div className="flex-1 flex flex-col items-center justify-center p-6 relative">

        {/* CALIBRATION UI */}
        {calibState !== 'DONE' ? (
          <div className="text-center animate-in zoom-in w-full max-w-xs">
            {calibState === 'NONE' && (
                <>
                    <Target size={64} className="text-gray-600 mx-auto mb-6" />
                    <h2 className="text-2xl font-black text-white mb-4">Calibration</h2>
                    <div className="bg-gym-800 p-4 rounded-xl mb-6 text-left">
                        <p className="text-xs text-gray-400 uppercase font-bold mb-2">Steps:</p>
                        <ol className="text-sm text-gray-300 list-decimal list-inside space-y-1">
                            <li>Get into starting position.</li>
                            <li>Wait for countdown.</li>
                            <li>Perform <strong>ONE PERFECT REP</strong>.</li>
                            <li>Full Range of Motion.</li>
                        </ol>
                    </div>
                    <button onClick={startCalibrationSequence} className="w-full py-4 bg-gym-accent text-white font-bold rounded-xl shadow-lg">Start Calibration</button>
                </>
            )}
            {calibState === 'COUNTDOWN' && (
                <>
                    <h1 className="text-9xl font-black text-white mb-4">{calibCount}</h1>
                    <p className="text-gym-accent font-bold uppercase animate-pulse">{feedbackMsg || "Get Ready..."}</p>
                </>
            )}
            {calibState === 'RECORDING' && (
                <>
                    <div className="w-32 h-32 rounded-full border-4 border-dashed border-red-500 animate-spin mx-auto mb-6"></div>
                    <h3 className="text-2xl font-bold text-white mb-2">Moving...</h3>
                    <p className="text-gray-400 mb-8 text-sm">{feedbackMsg || "Perform 1 Full Rep"}</p>
                    <button onClick={finishCalibration} className="w-full py-4 bg-red-600 text-white font-bold rounded-xl shadow-lg">Finish Rep</button>
                </>
            )}
          </div>
        ) : (
          <>
            {/* LIVE FEEDBACK TEXT */}
            <div className="absolute top-6 w-full text-center z-10 pointer-events-none">
                {feedbackMsg && (
                  <div className={`inline-flex items-center gap-2 px-4 py-2 text-white font-black rounded-full shadow-lg transition-all duration-300
                    ${processorEvent?.feedbackType === 'TOO_FAST' ? 'bg-red-500 animate-bounce' : 
                      processorEvent?.feedbackType === 'TOO_SLOW' ? 'bg-orange-500' : 'bg-gym-success'}
                  `}>
                    {processorEvent?.feedbackType === 'TOO_FAST' && <AlertTriangle size={18} />}
                    {feedbackMsg}
                  </div>
                )}
            </div>

            {/* MODE RENDERER */}
            <div className="w-full max-w-sm">
                {mode === 'GAME' ? (
                    <GamePacer 
                        progress={progress} 
                        phase={phase} 
                        isPaused={isPaused} 
                        pacerConfig={exercise.pacer} 
                    />
                ) : (
                    <div className="relative flex justify-center py-10">
                        <div className={`w-64 h-64 rounded-full border-8 border-gym-800 flex flex-col items-center justify-center transition-all duration-300 shadow-2xl`}>
                            <p className="text-[10px] text-gray-500 uppercase font-bold mb-1">Depth</p>
                            <h2 className="text-6xl font-black text-white tabular-nums">
                            {Math.round(progress * 100)}<span className="text-2xl text-gym-accent">%</span>
                            </h2>
                            <div className="mt-4 px-4 py-1 bg-gym-900 border border-gym-700 rounded-full text-xs font-bold text-gray-300">
                            {phase.replace('_', ' ')}
                            </div>
                        </div>
                        {/* Progress Ring */}
                        <svg className="absolute top-10 left-1/2 -translate-x-1/2 w-64 h-64 -rotate-90 pointer-events-none">
                            <circle cx="128" cy="128" r="120" stroke="currentColor" strokeWidth="8" fill="transparent" strokeDasharray={754} strokeDashoffset={754 - (754 * progress)} className="text-gym-accent transition-all duration-75" />
                        </svg>
                    </div>
                )}
            </div>

            <div className="mt-8 flex items-center justify-center gap-4">
               {!isManualMode && (
                   <button 
                     onClick={resetCalibration}
                     className="px-4 py-2 bg-gym-800 rounded-lg text-xs font-bold text-gray-400 border border-gym-700"
                   >
                       Recalibrate
                   </button>
               )}
               <button 
                 onClick={() => { setIsPaused(!isPaused); speak(isPaused ? "Resuming" : "Paused"); }}
                 className={`w-20 h-20 rounded-full flex items-center justify-center border-4 ${isPaused ? 'bg-gym-success border-white' : 'bg-gym-800 border-gym-700'} text-white shadow-xl transition-all active:scale-95`}
               >
                 {isPaused ? <Play size={32} fill="currentColor" /> : <Pause size={32} fill="currentColor" />}
               </button>
            </div>
          </>
        )}
      </div>

      {/* FOOTER */}
      <div className="p-6 bg-gym-800 border-t border-gym-700 flex justify-between items-center z-10">
        <div>
          <p className="text-[10px] text-gray-500 uppercase font-bold tracking-wider">Session Reps</p>
          <p className="text-5xl font-black text-white leading-none">
            {reps} <span className="text-xl text-gray-500 font-medium">/ {targetReps}</span>
          </p>
        </div>
        <button onClick={handleClose} className="px-8 py-4 bg-white text-gym-900 font-black rounded-2xl shadow-xl active:scale-95 transition-transform flex items-center gap-2">
          <CheckCircle size={20} /> FINISH SET
        </button>
      </div>
    </div>
  );
};

export default MotionTracker;

import { SessionData, UserStats, ExerciseHistory, HistoryLog, DashboardStats, MuscleGroup, Exercise, CoachRecommendation, MotionCalibration, UserProfile, SkippedEntry, PendingExercise, TempoRating, NutritionLog } from '../types';
import { ALL_WORKOUTS } from '../constants';

// --- KEY MANAGEMENT SYSTEM ---

const GLOBAL_KEYS = {
  USERS_REGISTRY: 'iron_guide_users_registry',
  ACTIVE_USER_ID: 'iron_guide_active_user_id',
};

// Base keys that will be prefixed with user ID
const BASE_KEYS = {
  SESSION: 'iron_guide_session_v2',
  STATS: 'iron_guide_stats_v2',
  HISTORY: 'iron_guide_history_v2',
  CALIBRATION: 'iron_guide_calibration_v2', // Updated version
  NOTES: 'iron_guide_notes_v1',
  SKIPPED: 'iron_guide_skipped_v1', 
  PENDING: 'iron_guide_pending_v1', 
  NUTRITION: 'iron_guide_nutrition_v1', 
};

// ... (Keep existing User Management, Migration, Backup logic identical) ...
// State to hold current user ID in memory
let currentUserId: string | null = localStorage.getItem(GLOBAL_KEYS.ACTIVE_USER_ID);

// Helper to get scoped key
const getKey = (baseKey: string) => {
  if (!currentUserId) return baseKey; // Fallback for legacy or error state
  return `user_${currentUserId}_${baseKey}`;
};

// --- USER MANAGEMENT ---

export const getUsers = (): UserProfile[] => {
  const raw = localStorage.getItem(GLOBAL_KEYS.USERS_REGISTRY);
  return raw ? JSON.parse(raw) : [];
};

export const createUser = (name: string): UserProfile => {
  const users = getUsers();
  const newUser: UserProfile = {
    id: Date.now().toString(),
    name,
    created: Date.now()
  };
  users.push(newUser);
  localStorage.setItem(GLOBAL_KEYS.USERS_REGISTRY, JSON.stringify(users));
  return newUser;
};

export const switchUser = (userId: string) => {
  currentUserId = userId;
  localStorage.setItem(GLOBAL_KEYS.ACTIVE_USER_ID, userId);
};

export const getCurrentUser = (): UserProfile | null => {
  if (!currentUserId) return null;
  const users = getUsers();
  return users.find(u => u.id === currentUserId) || null;
};

export const deleteUser = (userId: string) => {
  const users = getUsers().filter(u => u.id !== userId);
  localStorage.setItem(GLOBAL_KEYS.USERS_REGISTRY, JSON.stringify(users));
  const prefix = `user_${userId}_`;
  Object.keys(localStorage).forEach(key => {
    if (key.startsWith(prefix)) {
      localStorage.removeItem(key);
    }
  });
  if (currentUserId === userId) {
    currentUserId = null;
    localStorage.removeItem(GLOBAL_KEYS.ACTIVE_USER_ID);
  }
};

export const checkAndMigrateLegacyData = (): boolean => {
  const users = getUsers();
  if (users.length > 0) return false; 
  const hasHistory = localStorage.getItem(BASE_KEYS.HISTORY);
  const hasStats = localStorage.getItem(BASE_KEYS.STATS);
  if (hasHistory || hasStats) {
    const defaultUser = createUser("Default User");
    currentUserId = defaultUser.id;
    localStorage.setItem(GLOBAL_KEYS.ACTIVE_USER_ID, defaultUser.id);
    const move = (baseKey: string) => {
      const data = localStorage.getItem(baseKey);
      if (data) {
        localStorage.setItem(getKey(baseKey), data);
        localStorage.removeItem(baseKey);
      }
    };
    move(BASE_KEYS.SESSION);
    move(BASE_KEYS.STATS);
    move(BASE_KEYS.HISTORY);
    move(BASE_KEYS.CALIBRATION);
    return true; 
  }
  return false;
};

export const exportUserData = () => {
  if (!currentUserId) return null;
  const backup = {
    userProfile: getCurrentUser(),
    timestamp: Date.now(),
    data: {
      session: localStorage.getItem(getKey(BASE_KEYS.SESSION)),
      stats: localStorage.getItem(getKey(BASE_KEYS.STATS)),
      history: localStorage.getItem(getKey(BASE_KEYS.HISTORY)),
      calibration: localStorage.getItem(getKey(BASE_KEYS.CALIBRATION)),
      notes: localStorage.getItem(getKey(BASE_KEYS.NOTES)),
      skipped: localStorage.getItem(getKey(BASE_KEYS.SKIPPED)),
      pending: localStorage.getItem(getKey(BASE_KEYS.PENDING)),
      nutrition: localStorage.getItem(getKey(BASE_KEYS.NUTRITION)),
    }
  };
  const dataStr = "data:text/json;charset=utf-8," + encodeURIComponent(JSON.stringify(backup));
  const downloadAnchorNode = document.createElement('a');
  downloadAnchorNode.setAttribute("href", dataStr);
  const date = new Date().toISOString().split('T')[0];
  downloadAnchorNode.setAttribute("download", `ironguide_backup_${getCurrentUser()?.name}_${date}.json`);
  document.body.appendChild(downloadAnchorNode);
  downloadAnchorNode.click();
  downloadAnchorNode.remove();
};

export const importUserData = async (file: File): Promise<boolean> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const json = JSON.parse(event.target?.result as string);
        if (!json.userProfile || !json.data) {
          alert("Invalid backup file format.");
          return resolve(false);
        }
        if (!currentUserId) {
           alert("Please log in to a user before restoring.");
           return resolve(false);
        }
        if (json.data.session) localStorage.setItem(getKey(BASE_KEYS.SESSION), json.data.session);
        if (json.data.stats) localStorage.setItem(getKey(BASE_KEYS.STATS), json.data.stats);
        if (json.data.history) localStorage.setItem(getKey(BASE_KEYS.HISTORY), json.data.history);
        if (json.data.calibration) localStorage.setItem(getKey(BASE_KEYS.CALIBRATION), json.data.calibration);
        if (json.data.notes) localStorage.setItem(getKey(BASE_KEYS.NOTES), json.data.notes);
        if (json.data.skipped) localStorage.setItem(getKey(BASE_KEYS.SKIPPED), json.data.skipped);
        if (json.data.pending) localStorage.setItem(getKey(BASE_KEYS.PENDING), json.data.pending);
        if (json.data.nutrition) localStorage.setItem(getKey(BASE_KEYS.NUTRITION), json.data.nutrition);
        resolve(true);
      } catch (e) {
        console.error(e);
        alert("Failed to parse backup file.");
        resolve(false);
      }
    };
    reader.readAsText(file);
  });
};

